// Brisbane TVs — normalize lead, detect spam, build email
//
// n8n Webhook v2 wraps the POST under .body; unwrap defensively.
const raw = ($input.first() || {}).json || {};
const i = (raw && raw.body && typeof raw.body === 'object') ? raw.body : raw;

// Honeypot — `_bts_check` is the primary trap; legacy names belt-and-braces.
const isSpam = !!(i._bts_check || i.company_website || i.honeypot || i.hp);
if (isSpam) {
  return [{ json: { isSpam: true } }];
}

const safe = (v, d = '') => (v === undefined || v === null) ? d : String(v).trim();
const esc  = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');

const lead = i.lead || {};
const job = i.job || {};
const tracking = i.tracking || {};
const server = i.server || {};

const name     = safe(lead.name, '(no name provided)');
const phone    = safe(lead.phone);
const email    = safe(lead.email);
const suburb   = safe(lead.suburb);
const postcode = safe(lead.postcode);

const tvCount    = job.tv_count || 1;
const sizeTier   = safe(job.size_tier);
const sizeLabel  = safe(job.size_label, sizeTier);
const pkgLabel   = safe(job.package_label);
const tvSize     = safe(job.tv_size);
const tvBrand    = safe(job.tv_brand);
const addons     = Array.isArray(job.addons) ? job.addons : [];
const wall       = safe(job.wall_type);
const date       = safe(job.preferred_date);
const estimate   = job.estimate_aud;
const notes      = safe(job.notes);
const photos     = Array.isArray(job.photos_attached) ? job.photos_attached : [];

const source  = safe(i.source, 'unknown');
const pageUrl = safe(i.page_url);

const isSubscribe = source === 'newsletter' || source === 'subscribe';

// ---------- Subject line ----------
let subject;
if (isSubscribe) {
  subject = `New subscriber — ${email || name || 'no email'}`;
} else {
  const parts = [];
  if (pkgLabel)         parts.push(pkgLabel.replace(/—.*$/, '').trim());
  else if (sizeLabel)   parts.push(sizeLabel);
  if (suburb)           parts.push(suburb);
  if (estimate)         parts.push(`$${estimate}`);
  subject = `🟣 New lead${parts.length ? ' — ' + parts.join(' · ') : ''}`;
}

// ---------- Preheader (inbox preview text) ----------
const preheaderParts = [];
if (phone) preheaderParts.push(phone);
if (suburb) preheaderParts.push(suburb);
if (pkgLabel) preheaderParts.push(pkgLabel.replace(/—.*$/, '').trim());
const preheader = esc(preheaderParts.join(' · ') || 'New lead from brisbanetvs.com');

// ---------- Tap-to-call link ----------
const telHref = phone ? phone.replace(/[^\d+]/g, '') : '';

// ---------- Wall type label (humanize the slug) ----------
const wallLabels = {
  'plasterboard':       'Plasterboard (timber stud)',
  'plasterboard-steel': 'Plasterboard (steel stud)',
  'brick':              'Exposed / rendered brick',
  'concrete':           'Concrete / cement block',
  'fibro':              'Fibro / weatherboard',
  'tile':               'Tiled / feature wall',
  'not-sure':           'Customer not sure'
};
const wallLabel = wallLabels[wall] || wall;

// ---------- Add-on labels ----------
const addonLabels = {
  'cable-concealment': 'In-wall cable concealment',
  'soundbar':          'Soundbar mount',
  'above-fireplace':   'Above-fireplace lift',
  'power-relocation':  'New power point behind TV',
  'outdoor':           'Outdoor / alfresco install',
  'remove-old':        'Remove or relocate existing TV'
};
const addonsPretty = addons.map(a => addonLabels[a] || a);

// ---------- Preferred-date label ----------
const dateLabels = {
  'asap':                'ASAP — same day if possible',
  'weekday-morning':     'Weekday mornings',
  'weekday-afternoon':   'Weekday afternoons',
  'saturday':            'Saturday',
  'next-week':           'Next week',
  'flexible':            'Flexible'
};
const dateLabel = dateLabels[date] || date;

// ---------- Build the job-details rows ----------
const jobRows = [];
if (pkgLabel)
  jobRows.push(['Package', esc(pkgLabel)]);
if (tvSize || tvBrand)
  jobRows.push(['TV', esc([tvSize ? tvSize + '"' : '', tvBrand].filter(Boolean).join(' · ')) + (tvCount > 1 ? ` <span style="color:#94a3b8;">(×${tvCount})</span>` : '')]);
else if (tvCount > 1)
  jobRows.push(['TV count', String(tvCount)]);
if (!pkgLabel && sizeLabel)
  jobRows.push(['Size tier', esc(sizeLabel)]);
if (wallLabel)
  jobRows.push(['Wall', esc(wallLabel)]);
if (addonsPretty.length)
  jobRows.push(['Add-ons', '<ul style="margin:0;padding:0 0 0 18px;">' + addonsPretty.map(a => `<li>${esc(a)}</li>`).join('') + '</ul>']);
if (dateLabel)
  jobRows.push(['Preferred', esc(dateLabel)]);
if (estimate)
  jobRows.push(['Estimate', `<strong style="color:#0f172a;">$${esc(estimate)}</strong>`]);
if (photos.length)
  jobRows.push(['Photos', `${photos.length} attached <em style="color:#94a3b8;">— reply to ask for them</em><div style="margin-top:4px;font-size:12px;color:#94a3b8;">${photos.map(p => esc(p.name + ' (' + p.size_kb + ' KB)')).join('<br>')}</div>`]);

const jobRowsHtml = jobRows.map(([k, v]) =>
  `<tr><td style="padding:7px 0;color:#64748b;width:110px;vertical-align:top;">${k}</td><td style="padding:7px 0;color:#0f172a;">${v}</td></tr>`
).join('');

// ---------- Phone & email buttons ----------
const phoneBtn = phone
  ? `<a href="tel:${esc(telHref)}" style="display:inline-block;padding:13px 20px;background:#0f172a;color:#ffffff;text-decoration:none;border-radius:8px;font-size:15px;font-weight:600;margin:0 6px 6px 0;mso-padding-alt:0;">📞 ${esc(phone)}</a>`
  : '';
const emailBtn = email
  ? `<a href="mailto:${esc(email)}" style="display:inline-block;padding:13px 20px;background:#f1f5f9;color:#0f172a;text-decoration:none;border-radius:8px;font-size:15px;font-weight:600;border:1px solid #e2e8f0;margin:0 6px 6px 0;mso-padding-alt:0;">✉️ Reply to ${esc(email.split('@')[0])}</a>`
  : '';

// ---------- Final HTML ----------
const html = `<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<meta name="color-scheme" content="light">
<title>New lead — Brisbane TVs</title>
</head>
<body style="margin:0;padding:0;background:#f3f4f6;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;color:#0f172a;-webkit-text-size-adjust:100%;">
<div style="display:none;max-height:0;overflow:hidden;font-size:1px;color:#f3f4f6;line-height:1px;mso-hide:all;">${preheader}</div>
<table role="presentation" cellpadding="0" cellspacing="0" width="100%" style="background:#f3f4f6;">
  <tr><td align="center" style="padding:28px 16px;">
    <table role="presentation" cellpadding="0" cellspacing="0" width="100%" style="max-width:580px;">

      <!-- Brand strip -->
      <tr><td style="padding:0 4px 14px 4px;">
        <div style="font-size:12px;font-weight:700;letter-spacing:1.5px;text-transform:uppercase;color:#403ed0;">
          ▸ Brisbane TVs · Lead Notification
        </div>
      </td></tr>

      <!-- Main card -->
      <tr><td style="background:#ffffff;border-radius:14px;box-shadow:0 1px 3px rgba(15,23,42,0.06);overflow:hidden;">

        <!-- Customer header -->
        <table role="presentation" cellpadding="0" cellspacing="0" width="100%">
          <tr><td style="padding:28px 28px 20px 28px;">
            <div style="font-size:11px;letter-spacing:1.5px;text-transform:uppercase;color:${isSubscribe ? '#64748b' : '#16a34a'};font-weight:700;margin-bottom:6px;">
              ${isSubscribe ? '★ New subscriber' : '★ New lead'}
            </div>
            <h1 style="margin:0 0 6px 0;font-size:28px;font-weight:700;color:#0f172a;line-height:1.15;letter-spacing:-0.01em;">
              ${esc(name)}
            </h1>
            ${(suburb || postcode) ? `<div style="font-size:14px;color:#64748b;">📍 ${esc([suburb, postcode].filter(Boolean).join(' · '))}</div>` : ''}

            <!-- Contact buttons -->
            <div style="margin-top:18px;">
              ${phoneBtn}${emailBtn}
            </div>
          </td></tr>
        </table>

        ${jobRowsHtml ? `
        <!-- Job details -->
        <table role="presentation" cellpadding="0" cellspacing="0" width="100%">
          <tr><td style="padding:0 28px;">
            <div style="border-top:1px solid #e2e8f0;"></div>
          </td></tr>
          <tr><td style="padding:20px 28px 8px 28px;">
            <div style="font-size:11px;letter-spacing:1.2px;text-transform:uppercase;color:#94a3b8;font-weight:700;margin-bottom:12px;">
              Job details
            </div>
            <table role="presentation" cellpadding="0" cellspacing="0" width="100%" style="font-size:14px;line-height:1.55;">
              ${jobRowsHtml}
            </table>
          </td></tr>
        </table>` : ''}

        ${notes ? `
        <!-- Customer notes — highlighted -->
        <table role="presentation" cellpadding="0" cellspacing="0" width="100%">
          <tr><td style="padding:10px 28px 14px 28px;">
            <div style="background:#fef3c7;border-left:3px solid #f59e0b;padding:14px 16px;border-radius:6px;">
              <div style="font-size:11px;letter-spacing:1px;text-transform:uppercase;color:#92400e;font-weight:700;margin-bottom:4px;">
                Customer notes
              </div>
              <div style="font-size:14px;line-height:1.55;color:#451a03;white-space:pre-wrap;">${esc(notes)}</div>
            </div>
          </td></tr>
        </table>` : ''}

        <!-- Metadata footer -->
        <table role="presentation" cellpadding="0" cellspacing="0" width="100%">
          <tr><td style="padding:0 28px;">
            <div style="border-top:1px solid #e2e8f0;"></div>
          </td></tr>
          <tr><td style="padding:16px 28px 24px 28px;">
            <div style="font-size:11px;color:#94a3b8;line-height:1.75;">
              <strong style="color:#64748b;font-weight:600;">Source:</strong> ${esc(source)}${pageUrl ? ` · <a href="${esc(pageUrl)}" style="color:#94a3b8;text-decoration:underline;">${esc(pageUrl.replace(/^https?:\/\//, ''))}</a>` : ''}<br>
              ${(tracking.utm_source || tracking.utm_campaign) ? `<strong style="color:#64748b;font-weight:600;">UTM:</strong> ${esc([tracking.utm_source, tracking.utm_medium, tracking.utm_campaign].filter(Boolean).join(' / '))}<br>` : ''}
              ${tracking.referrer ? `<strong style="color:#64748b;font-weight:600;">Referrer:</strong> ${esc(tracking.referrer)}<br>` : ''}
              ${server.ip ? `<strong style="color:#64748b;font-weight:600;">IP:</strong> ${esc(server.ip)}${server.country ? ` (${esc(server.country)})` : ''}` : ''}
            </div>
          </td></tr>
        </table>

      </td></tr>

      <!-- Tagline footer -->
      <tr><td align="center" style="padding:16px 0 4px 0;font-size:11px;color:#94a3b8;letter-spacing:0.3px;">
        Brisbane TVs · automated lead notification
      </td></tr>

    </table>
  </td></tr>
</table>
</body>
</html>`;

return [{
  json: {
    isSpam: false,
    subject,
    preheader,
    html,
    name, phone, email, suburb, postcode,
    source, pageUrl,
    tvCount, sizeTier, sizeLabel, pkgLabel, tvSize, tvBrand, addons, wall, date, estimate, notes, photos
  }
}];
